#!/bin/bash
set -e

echo "🚀 Setting up Kafka Learning Guide..."

# Create folder structure
mkdir -p css js diagrams data

# Move root-level files to correct locations if they exist there
[ -f style.css ] && mv style.css css/style.css && echo "  Moved style.css → css/style.css"
[ -f app.js ]    && mv app.js    js/app.js     && echo "  Moved app.js → js/app.js"

echo "📁 Folder structure ready"
echo ""
echo "📄 Writing all HTML files..."
echo "  Writing advanced.html..."
echo '' | base64 -d > advanced.html
echo "  Writing architecture.html..."
echo '' | base64 -d > architecture.html
echo "  Writing cheatsheet.html..."
echo '' | base64 -d > cheatsheet.html
echo "  Writing comparison.html..."
echo '' | base64 -d > comparison.html
echo "  Writing index.html..."
echo '' | base64 -d > index.html
echo "  Writing interview.html..."
echo '' | base64 -d > interview.html
echo "  Writing operations.html..."
echo '' | base64 -d > operations.html
echo "  Writing performance.html..."
echo '' | base64 -d > performance.html
echo "  Writing roadmap.html..."
echo '' | base64 -d > roadmap.html
echo "  Writing security.html..."
echo '' | base64 -d > security.html
echo "  Writing usecases.html..."
echo '' | base64 -d > usecases.html
echo "  Writing css/style.css..."
echo '' | base64 -d > css/style.css
echo "  Writing js/app.js..."
echo '' | base64 -d > js/app.js

echo ""
echo "✅ All files written!"
echo ""
echo "📦 Committing to git..."
git add -A
git commit -m "feat: add all pages — architecture, advanced, security, ops, cheatsheet, interview, performance, comparison, roadmap, usecases"
git push

echo ""
echo "🎉 Done! Your Kafka Learning Guide is fully deployed."